BEGIN;

CREATE TEMP TABLE tmp_paises (
  id uuid,
  codigo_iso2 char(2),
  codigo_iso3 char(3),
  nombre text,
  moneda text,
  simbolo_moneda text,
  activo boolean,
  created_at timestamptz
);

CREATE TEMP TABLE tmp_departamentos (
  id uuid,
  pais_id uuid,
  codigo_dane char(2),
  nombre text,
  activo boolean,
  created_at timestamptz
);

CREATE TEMP TABLE tmp_municipios (
  id uuid,
  departamento_id uuid,
  codigo_dane char(5),
  nombre text,
  es_capital boolean,
  activo boolean,
  created_at timestamptz
);

CREATE TEMP TABLE tmp_tenants (
  id uuid,
  slug text,
  nombre text,
  config jsonb,
  activo boolean,
  created_at timestamptz
);

CREATE TEMP TABLE tmp_tenants_detalles (
  id uuid,
  tenant_id uuid,
  razon_social text,
  nit text,
  dv text,
  tipo_persona text,
  tipo_sociedad text,
  fecha_constitucion date,
  estado text,
  responsabilidades_dian text,
  regimen text,
  actividad_economica text,
  obligado_facturacion_electronica boolean,
  resolucion_dian text,
  fecha_inicio_facturacion date,
  direccion_principal text,
  ciudad text,
  departamento text,
  pais text,
  telefono text,
  email_corporativo text,
  sitio_web text,
  representante_nombre text,
  representante_tipo_documento text,
  representante_numero_documento text,
  representante_email text,
  representante_telefono text,
  cuenta_contable_defecto text,
  banco_principal text,
  numero_cuenta text,
  tipo_cuenta text,
  created_at timestamptz,
  updated_at timestamptz,
  pais_id uuid,
  departamento_id uuid,
  municipio_id uuid
);

CREATE TEMP TABLE tmp_tenant_branches (
  id uuid,
  tenant_id uuid,
  codigo text,
  nombre text,
  descripcion text,
  es_principal boolean,
  direccion text,
  ciudad text,
  departamento text,
  pais text,
  telefono text,
  email text,
  estado text,
  metadata jsonb,
  created_at timestamptz,
  updated_at timestamptz,
  pais_id uuid,
  departamento_id uuid,
  municipio_id uuid
);

CREATE TEMP TABLE tmp_personas (
  id uuid,
  tenant_id uuid,
  nombres text,
  apellidos text,
  documento_tipo text,
  documento_numero text,
  telefono text,
  direccion text,
  email_personal text,
  cargo_nombre text,
  cargo_descripcion text,
  funciones_descripcion text,
  created_at timestamptz
);







SELECT p.id, p.codigo_iso2, p.codigo_iso3, p.nombre, p.moneda, p.simbolo_moneda, p.activo, p.created_at
FROM tmp_paises p
ON CONFLICT (codigo_iso2) DO UPDATE
SET
  codigo_iso3 = EXCLUDED.codigo_iso3,
  nombre = EXCLUDED.nombre,
  moneda = EXCLUDED.moneda,
  simbolo_moneda = EXCLUDED.simbolo_moneda,
  activo = EXCLUDED.activo;

SELECT
  d.id,
  p_real.id AS pais_id,
  d.codigo_dane,
  d.nombre,
  d.activo,
  d.created_at
FROM tmp_departamentos d
JOIN tmp_paises p_dump ON p_dump.id = d.pais_id
JOIN public.paises p_real ON p_real.codigo_iso2 = p_dump.codigo_iso2
ON CONFLICT (pais_id, codigo_dane) DO UPDATE
SET
  nombre = EXCLUDED.nombre,
  activo = EXCLUDED.activo;

SELECT
  m.id,
  d_real.id AS departamento_id,
  m.codigo_dane,
  m.nombre,
  m.es_capital,
  m.activo,
  m.created_at
FROM tmp_municipios m
JOIN tmp_departamentos d_dump ON d_dump.id = m.departamento_id
JOIN tmp_paises p_dump ON p_dump.id = d_dump.pais_id
JOIN public.paises p_real ON p_real.codigo_iso2 = p_dump.codigo_iso2
JOIN public.departamentos d_real
  ON d_real.pais_id = p_real.id
 AND d_real.codigo_dane = d_dump.codigo_dane
ON CONFLICT (departamento_id, codigo_dane) DO UPDATE
SET
  nombre = EXCLUDED.nombre,
  es_capital = EXCLUDED.es_capital,
  activo = EXCLUDED.activo;

SELECT t.id, t.slug, t.nombre, t.config, t.activo, t.created_at
FROM tmp_tenants t
ON CONFLICT (slug) DO UPDATE
SET
  nombre = EXCLUDED.nombre,
  config = EXCLUDED.config,
  activo = EXCLUDED.activo;

  id,
  tenant_id,
  razon_social,
  nit,
  dv,
  tipo_persona,
  tipo_sociedad,
  fecha_constitucion,
  estado,
  responsabilidades_dian,
  regimen,
  actividad_economica,
  obligado_facturacion_electronica,
  resolucion_dian,
  fecha_inicio_facturacion,
  direccion_principal,
  ciudad,
  departamento,
  pais,
  telefono,
  email_corporativo,
  sitio_web,
  representante_nombre,
  representante_tipo_documento,
  representante_numero_documento,
  representante_email,
  representante_telefono,
  cuenta_contable_defecto,
  banco_principal,
  numero_cuenta,
  tipo_cuenta,
  created_at,
  updated_at,
  pais_id,
  departamento_id,
  municipio_id
)
SELECT
  td.id,
  t_real.id AS tenant_id,
  td.razon_social,
  td.nit,
  td.dv,
  td.tipo_persona,
  td.tipo_sociedad,
  td.fecha_constitucion,
  td.estado,
  td.responsabilidades_dian,
  td.regimen,
  td.actividad_economica,
  td.obligado_facturacion_electronica,
  td.resolucion_dian,
  td.fecha_inicio_facturacion,
  td.direccion_principal,
  td.ciudad,
  td.departamento,
  td.pais,
  td.telefono,
  td.email_corporativo,
  td.sitio_web,
  td.representante_nombre,
  td.representante_tipo_documento,
  td.representante_numero_documento,
  td.representante_email,
  td.representante_telefono,
  td.cuenta_contable_defecto,
  td.banco_principal,
  td.numero_cuenta,
  td.tipo_cuenta,
  td.created_at,
  td.updated_at,
  p_real.id AS pais_id,
  d_real.id AS departamento_id,
  m_real.id AS municipio_id
FROM tmp_tenants_detalles td
JOIN tmp_tenants t_dump ON t_dump.id = td.tenant_id
JOIN public.tenants t_real ON t_real.slug = t_dump.slug
LEFT JOIN tmp_paises p_dump ON p_dump.id = td.pais_id
LEFT JOIN public.paises p_real ON p_real.codigo_iso2 = p_dump.codigo_iso2
LEFT JOIN tmp_departamentos d_dump ON d_dump.id = td.departamento_id
LEFT JOIN public.departamentos d_real
  ON p_real.id IS NOT NULL
 AND d_real.pais_id = p_real.id
 AND d_real.codigo_dane = d_dump.codigo_dane
LEFT JOIN tmp_municipios m_dump ON m_dump.id = td.municipio_id
LEFT JOIN public.municipios m_real
  ON d_real.id IS NOT NULL
 AND m_real.departamento_id = d_real.id
 AND m_real.codigo_dane = m_dump.codigo_dane
ON CONFLICT (tenant_id) DO UPDATE
SET
  razon_social = EXCLUDED.razon_social,
  nit = EXCLUDED.nit,
  dv = EXCLUDED.dv,
  tipo_persona = EXCLUDED.tipo_persona,
  tipo_sociedad = EXCLUDED.tipo_sociedad,
  fecha_constitucion = EXCLUDED.fecha_constitucion,
  estado = EXCLUDED.estado,
  responsabilidades_dian = EXCLUDED.responsabilidades_dian,
  regimen = EXCLUDED.regimen,
  actividad_economica = EXCLUDED.actividad_economica,
  obligado_facturacion_electronica = EXCLUDED.obligado_facturacion_electronica,
  resolucion_dian = EXCLUDED.resolucion_dian,
  fecha_inicio_facturacion = EXCLUDED.fecha_inicio_facturacion,
  direccion_principal = EXCLUDED.direccion_principal,
  ciudad = EXCLUDED.ciudad,
  departamento = EXCLUDED.departamento,
  pais = EXCLUDED.pais,
  telefono = EXCLUDED.telefono,
  email_corporativo = EXCLUDED.email_corporativo,
  sitio_web = EXCLUDED.sitio_web,
  representante_nombre = EXCLUDED.representante_nombre,
  representante_tipo_documento = EXCLUDED.representante_tipo_documento,
  representante_numero_documento = EXCLUDED.representante_numero_documento,
  representante_email = EXCLUDED.representante_email,
  representante_telefono = EXCLUDED.representante_telefono,
  cuenta_contable_defecto = EXCLUDED.cuenta_contable_defecto,
  banco_principal = EXCLUDED.banco_principal,
  numero_cuenta = EXCLUDED.numero_cuenta,
  tipo_cuenta = EXCLUDED.tipo_cuenta,
  updated_at = now(),
  pais_id = EXCLUDED.pais_id,
  departamento_id = EXCLUDED.departamento_id,
  municipio_id = EXCLUDED.municipio_id;

  id,
  tenant_id,
  codigo,
  nombre,
  descripcion,
  es_principal,
  direccion,
  ciudad,
  departamento,
  pais,
  telefono,
  email,
  estado,
  metadata,
  created_at,
  updated_at,
  pais_id,
  departamento_id,
  municipio_id
)
SELECT
  tb.id,
  t_real.id AS tenant_id,
  tb.codigo,
  tb.nombre,
  tb.descripcion,
  tb.es_principal,
  tb.direccion,
  tb.ciudad,
  tb.departamento,
  tb.pais,
  tb.telefono,
  tb.email,
  tb.estado,
  COALESCE(tb.metadata, '{}'::jsonb),
  tb.created_at,
  tb.updated_at,
  p_real.id AS pais_id,
  d_real.id AS departamento_id,
  m_real.id AS municipio_id
FROM tmp_tenant_branches tb
JOIN tmp_tenants t_dump ON t_dump.id = tb.tenant_id
JOIN public.tenants t_real ON t_real.slug = t_dump.slug
LEFT JOIN tmp_paises p_dump ON p_dump.id = tb.pais_id
LEFT JOIN public.paises p_real ON p_real.codigo_iso2 = p_dump.codigo_iso2
LEFT JOIN tmp_departamentos d_dump ON d_dump.id = tb.departamento_id
LEFT JOIN public.departamentos d_real
  ON p_real.id IS NOT NULL
 AND d_real.pais_id = p_real.id
 AND d_real.codigo_dane = d_dump.codigo_dane
LEFT JOIN tmp_municipios m_dump ON m_dump.id = tb.municipio_id
LEFT JOIN public.municipios m_real
  ON d_real.id IS NOT NULL
 AND m_real.departamento_id = d_real.id
 AND m_real.codigo_dane = m_dump.codigo_dane
ON CONFLICT (tenant_id, codigo) DO UPDATE
SET
  nombre = EXCLUDED.nombre,
  descripcion = EXCLUDED.descripcion,
  es_principal = EXCLUDED.es_principal,
  direccion = EXCLUDED.direccion,
  ciudad = EXCLUDED.ciudad,
  departamento = EXCLUDED.departamento,
  pais = EXCLUDED.pais,
  telefono = EXCLUDED.telefono,
  email = EXCLUDED.email,
  estado = EXCLUDED.estado,
  metadata = EXCLUDED.metadata,
  updated_at = now(),
  pais_id = EXCLUDED.pais_id,
  departamento_id = EXCLUDED.departamento_id,
  municipio_id = EXCLUDED.municipio_id;

  id,
  tenant_id,
  nombres,
  apellidos,
  documento_tipo,
  documento_numero,
  telefono,
  direccion,
  email_personal,
  cargo_nombre,
  cargo_descripcion,
  funciones_descripcion,
  created_at
)
SELECT
  p.id,
  t_real.id AS tenant_id,
  p.nombres,
  p.apellidos,
  p.documento_tipo,
  p.documento_numero,
  p.telefono,
  p.direccion,
  p.email_personal,
  p.cargo_nombre,
  p.cargo_descripcion,
  p.funciones_descripcion,
  p.created_at
FROM tmp_personas p
JOIN tmp_tenants t_dump ON t_dump.id = p.tenant_id
JOIN public.tenants t_real ON t_real.slug = t_dump.slug
ON CONFLICT (tenant_id, documento_numero) DO UPDATE
SET
  nombres = EXCLUDED.nombres,
  apellidos = EXCLUDED.apellidos,
  documento_tipo = EXCLUDED.documento_tipo,
  telefono = EXCLUDED.telefono,
  direccion = EXCLUDED.direccion,
  email_personal = EXCLUDED.email_personal,
  cargo_nombre = EXCLUDED.cargo_nombre,
  cargo_descripcion = EXCLUDED.cargo_descripcion,
  funciones_descripcion = EXCLUDED.funciones_descripcion;

COMMIT;
